let globalIndex = 0;

function TechBadgeCard({ tech, index }: { tech: TechBadge; index: number }) {
  return (
    <motion.div
      data-ocid={`tech-stack.item.${index + 1}`}
      initial={{ opacity: 0, scale: 0.85 }}
      whileInView={{ opacity: 1, scale: 1 }}
      viewport={{ once: true }}
      transition={{ duration: 0.4, delay: (index % 12) * 0.04 }}
      className="group flex flex-col items-center gap-2 p-4 rounded-xl border border-border/50 bg-card/60 hover:border-border hover:shadow-glass hover:scale-105 transition-smooth cursor-default backdrop-blur-sm"
    >
      <span
        className="w-11 h-11 flex items-center justify-center rounded-lg transition-smooth group-hover:scale-110"
        style={{
          background: `${tech.color}18`,
          border: `1px solid ${tech.color}30`,
        }}
      >
        {tech.icon}
      </span>
      <span className="text-xs font-semibold text-foreground/80 text-center leading-tight">
        {tech.name}
      </span>
    </motion.div>
  );
}

